#include <bits/stdc++.h>
using namespace std;
const int maxn=1e7+5;
struct node{
	int l,r;
}v[maxn];
long long n,a[maxn],s[maxn],top,ans1,ans2;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		while(top&&a[s[top]]>a[i]){
			v[i].l=s[top];
			top--;
		}
		if(top){
			v[s[top]].r=i;
		} 
		s[++top]=i;
	}
	for(int i=1;i<=n;i++){
		ans1^=i*(v[i].l+1ll);
		ans2^=i*(v[i].r+1ll);
	}
	cout<<ans1<<" "<<ans2;
	return 0;
}
